import collections

class Solution:
    def min_cost_tickets(self, days: list[int], costs: list[int]) -> int:
        last_day = days[-1]

        travel_days = set(days)

        dp = [0] * (last_day + 1)

        for i in range(1, last_day + 1):
            if i not in travel_days:
                dp[i] = dp[i-1]
            else:
                cost_1_day_pass = dp[i-1] + costs[0]

                cost_7_day_pass = dp[max(0, i-7)] + costs[1]

                cost_30_day_pass = dp[max(0, i-30)] + costs[2]

                dp[i] = min(cost_1_day_pass, cost_7_day_pass, cost_30_day_pass)

        return dp[last_day]
